import React, { useEffect, useState } from 'react';

const OAuthApp = () => {
  const [accessToken, setAccessToken] = useState(null);
  const clientId = 'your-client-id';
  const redirectUri = encodeURIComponent('https://your-redirect-uri.com/callback');
  const authorizationUrl = `https://oauth-provider.com/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=read%20write&state=random-state`;

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      exchangeCodeForToken(code);
    }
  }, []);

  const handleLogin = () => {
    window.location.href = authorizationUrl;
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch('https://oauth-provider.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: redirectUri,
          client_id: clientId,
          code_verifier: generateCodeVerifier()
        })
      });

      if (!response.ok) {
        throw new Error('Failed to exchange code for token');
      }

      const data = await response.json();
      setAccessToken(data.access_token);
      localStorage.setItem('access_token', data.access_token);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  const generateCodeVerifier = () => {
    const array = new Uint32Array(16);
    window.crypto.getRandomValues(array);
    return btoa(String.fromCharCode(...array)).replace(/[+/]/g, '').slice(0, 43);
  };

  const fetchApiData = async () => {
    try {
      const token = localStorage.getItem('access_token');
      if (!token) {
        throw new Error('No access token found');
      }

      const response = await fetch('https://api-provider.com/data', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (!response.ok) {
        throw new Error('Failed to fetch API data');
      }

      const data = await response.json();
      console.log(data);
    } catch (error) {
      console.error('Error fetching API data:', error);
    }
  };

  return (
    <div>
      {accessToken ? (
        <button onClick={fetchApiData}>Fetch Data</button>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
};

export default OAuthApp;